// tibashi-js/modal/time.js
import { ENDPOINTS } from "../../utils.js";

export async function renderTimes(ev, tabContent) {
  // Show loader while fetching
  tabContent.innerHTML = `
    <div class="loader loader-dots">
      <div></div><div></div><div></div>
    </div>
  `;

  // Map tags to labels
  function getOrderLabel(tag) {
    return (
      {
        101: "تمدید شد",
        102: "اجرای ویژه",
        103: "روزهای پایانی",
        104: "ساعت متفاوت",
        105: "تخفیف ویژه",
        106: "بلیت تمام شد",
        107: "تخفیف آغازین",
        999: "اجرای پایانی",
      }[tag] || ""
    );
  }

  try {
    // Fetch times
    const res = await fetch(ENDPOINTS.times(ev.id));
    const data = await res.json();
    if (!data.status) throw new Error(data.message || "داده نامعتبر است");
    const times = data.result.times;

    // Fetch capacity
    let capMap = {};
    if (times.some((t) => t.tag !== 33 && t.tag !== 66)) {
      const capRes = await fetch(ENDPOINTS.capacity(ev.id));
      const capData = await capRes.json();
      if (capData.result) capData.result.forEach((c) => (capMap[c.sansId] = c));
    }

    // Render container
    tabContent.innerHTML = `<div class="scroll-x"></div>`;
    const scrollContainer = tabContent.querySelector(".scroll-x");

    // Render each time card
  // Inside times.forEach
times.forEach((s) => {
  const cap = capMap[s.id];
  const reserved = cap?.reserved ?? 0;
  const soldOut = s.tag === 106 || cap?.soldout;
  const fullness = cap?.capacity
    ? Math.round((reserved / cap.capacity) * 100)
    : 0;

  const div = document.createElement("div");
  div.className = "tibashi-sans-card";

  const buttonText = soldOut ? "بلیت تمام شد" : "خرید";
  const buttonDisabled = soldOut ? "disabled" : "";

  // Keep title outside initially
  const titleDiv = document.createElement("div");
  titleDiv.className = "tibashi-sans-title";
  titleDiv.textContent = s.persian;

  div.innerHTML = `
    <div class="tibashi-sans-sub">${getOrderLabel(s.tag)}</div>
    <div class="tibashi-progress-bar">
      <div class="tibashi-progress-fill" style="width:${fullness}%"></div>
    </div>
    <button 
      class="tibashi-sans-btn" 
      ${buttonDisabled} 
      data-event-id="${s.events}" 
      data-time-id="${s.id}"
    >
      <img 
        src="../tibashi-asset/icons/archive-down-minimlistic-svgrepo-com.svg" 
        alt="icon" 
        class="tibashi-sans-btn-icon"
      />
      ${buttonText}
    </button>
  `;

  div.prepend(titleDiv); // initially show title outside button
  scrollContainer.appendChild(div);

  const btn = div.querySelector(".tibashi-sans-btn");

  // Button click behavior
  btn.addEventListener("click", async (e) => {
    e.stopPropagation();
    if (btn.disabled) return;

    const prevActiveBtn = scrollContainer.querySelector(".tibashi-sans-btn.active");
    const prevTitle = scrollContainer.querySelector(".tibashi-sans-title.inside");
    if (prevActiveBtn) {
      prevActiveBtn.classList.remove("active");
      const prevIcon = prevActiveBtn.querySelector(".tibashi-sans-btn-icon");
      if (prevIcon)
        prevIcon.src = "../tibashi-asset/icons/archive-down-minimlistic-svgrepo-com.svg";

      // Move previous title back outside button
      if (prevTitle) {
        prevTitle.classList.remove("inside");
        prevActiveBtn.parentElement.prepend(prevTitle);
        prevActiveBtn.querySelector(".tibashi-sans-btn-text")?.remove();
      }
    }

    // Set current button as active
    btn.classList.add("active");
    const icon = btn.querySelector(".tibashi-sans-btn-icon");
    if (icon)
      icon.src = "../tibashi-asset/icons/archive-minimalistic-svgrepo-com.svg";

    // Move title inside button
    titleDiv.classList.add("inside");
    btn.innerHTML = ""; // clear button content
    btn.appendChild(icon); // re-add icon
    btn.appendChild(titleDiv); // move title inside

    // Render seat map
    const eventId = btn.getAttribute("data-event-id");
    const timeId = btn.getAttribute("data-time-id");
    const event = { eventId, timeId };
    const { renderSeats } = await import("../modal/seat/SeatMap.js");
    await renderSeats(event, eventId);
  });
});

  } catch (err) {
    tabContent.innerHTML = `<div class="tibashi-error">خطا در بارگذاری زمان‌ها</div>`;
    console.error(err);
  }
}
